if (!msg.measurement) return null;

// Usa a medição antiga como nome da Collection no Mongo
msg.collection = msg.measurement;

// Embrulha o documento JSON com timestamp
msg.payload = {
    timestamp: new Date(),
    dados: msg.payload
};

return msg;

var isBkp = (msg.topic.indexOf('backup') !== -1);
var v = msg.payload.val;
var tp = msg.payload.tipo || (isBkp ? 'BACKUP' : 'REALTIME');
var m_inf = {measurement:'Parametros_Pressao_Tensao', payload:{tensao:v, origem:tp}};
if(!isBkp) return [m_inf, {payload:v}];
return [m_inf, null];

var isBkp = (msg.topic.indexOf('backup') !== -1);
var v = msg.payload.val;
var tp = msg.payload.tipo || (isBkp ? 'BACKUP' : 'REALTIME');
var m_inf = {measurement:'Parametros_Temperatura', payload:{temperatura:v, origem:tp}};
if(!isBkp) return [m_inf, {payload:v}];
return [m_inf, null];

var p = msg.payload.p;
var t = 8; // Total de partes

if (!p) return null;

// GATILHO DE SEGURANÇA: Se chegar a parte 1, é um ciclo novo. 
// Limpa o lixo da memória caso a rede tenha perdido algum pacote no ciclo anterior.
if (p === 1) {
  context.set('bX', {}); context.set('bY', {}); context.set('bZ', {}); context.set('cnt', 0);
}

var bX = context.get('bX') || {};
var bY = context.get('bY') || {};
var bZ = context.get('bZ') || {};
var cnt = context.get('cnt') || 0;

// Salva a amostra se ainda não tiver recebido esta parte
if (!bX[p]) {
  bX[p] = msg.payload.x;
  bY[p] = msg.payload.y;
  bZ[p] = msg.payload.z;
  cnt++;
}

// Quando juntar as 8 peças do quebra-cabeça, dispara para o gráfico!
if (cnt >= t) {
  var fX = [], fY = [], fZ = [];
  for (var i = 1; i <= t; i++) {
    if (bX[i]) fX = fX.concat(bX[i]);
    if (bY[i]) fY = fY.concat(bY[i]);
    if (bZ[i]) fZ = fZ.concat(bZ[i]);
  }

  context.set('bX', {}); context.set('bY', {}); context.set('bZ', {}); context.set('cnt', 0);

  msg.payload = {
    tipo: 'REALTIME_FULL',
    x: fX, y: fY, z: fZ,
    x_samples: fX, y_samples: fY, z_samples: fZ
  };
  return msg;
}

context.set('bX', bX); context.set('bY', bY); context.set('bZ', bZ); context.set('cnt', cnt);
return null;

if (msg.payload.tipo === 'REALTIME_FULL') {
  var mensagens = [];

  // Cria um tempo base retroativo (separa as amostras artificialmente em milissegundos)
  // Isso impede o Node-RED de esmagar todos os 512 pontos no mesmo pixel da tela.
  var tempoBase = new Date().getTime() - msg.payload.x.length;

  for (var i = 0; i < msg.payload.x.length; i++) {
    var t = tempoBase + i;
    mensagens.push({ topic: 'X', payload: msg.payload.x[i], timestamp: t });
    mensagens.push({ topic: 'Y', payload: msg.payload.y[i], timestamp: t });
    mensagens.push({ topic: 'Z', payload: msg.payload.z[i], timestamp: t });
  }
  return [mensagens];
}
return null;

