var data = msg.payload.x; // Mude para .y ou .z
var eixo = "x";           // Mude para "y" ou "z"
var sensor = "s1";        // Mude para "s2" ou "s3"
// ======================================================

if (!Array.isArray(data) || data.length === 0) return null;

var sr = 800, sz = 1024;
var n_samples = data.length;

// 1. Calcula a média (Remove o DC Offset) para matar o pico de 384Hz
var sum = 0;
for (var i = 0; i < n_samples; i++) sum += data[i];
var mean = sum / n_samples;

// 2. Preenche os arrays aplicando a correção e o Zero-Padding
var re = new Float32Array(sz), im = new Float32Array(sz);
for (var i = 0; i < sz; i++) {
    if (i < n_samples) re[i] = data[i] - mean;
    else re[i] = 0;
}

// 3. Matemática bruta da FFT
var N = sz;
for (var i = 0; i < N; i++) {
    var k = N, j = 0;
    for (var l = 1; l < N; l *= 2) { k >>= 1; j += k * ((i / l) % 2 | 0); }
    if (j > i) { var t = re[i]; re[i] = re[j]; re[j] = t; }
}
for (var l = 2; l <= N; l *= 2) {
    var wRe = Math.cos(-2 * Math.PI / l), wIm = Math.sin(-2 * Math.PI / l);
    for (var i = 0; i < N; i += l) {
        var uRe = 1, uIm = 0;
        for (var j = 0; j < l / 2; j++) {
            var reIdx = i + j, imIdx = i + j + l / 2;
            var tRe = uRe * re[imIdx] - uIm * im[imIdx];
            var tIm = uRe * im[imIdx] + uIm * re[imIdx];
            re[imIdx] = re[reIdx] - tRe; im[imIdx] = im[reIdx] - tIm;
            re[reIdx] += tRe; im[reIdx] += tIm;
            var nURe = uRe * wRe - uIm * wIm;
            uIm = uRe * wIm + uIm * wRe; uRe = nURe;
        }
    }
}

// 4. Busca os picos e monta o espectro
var pM = 0, pI = 0, pts = [];
for (var k = 4; k < sz / 2; k++) {
    var mag = Math.sqrt(re[k] * re[k] + im[k] * im[k]) / (sz / 2);
    if (mag > 0.5) { // Limiar de ruído
        pts.push([{ magnitude: mag, frequency: k * (sr / sz) }, { axis: eixo, sensor: sensor.toUpperCase() }]);
        if (mag > pM) { pM = mag; pI = k; }
    }
}
var fP = pI * (sr / sz);

// 5. Monta os pacotes dinamicamente para o Node-RED e MongoDB
var m_p = {
    measurement: "accelfft_" + eixo + "_" + sensor,
    payload: {}
};
m_p.payload["frequencia_pico_" + eixo] = fP;
m_p.payload["magnitude_pico_" + eixo] = pM;

var m_s = {
    measurement: "accelfft_spectrum_" + eixo + "_" + sensor,
    payload: pts
};
var m_d = { payload: fP.toFixed(2) + " Hz" };

if (pts.length === 0) m_s = null;
return [m_p, m_s, m_d];

